#ifndef GEMM_N256_K7168_KERNEL_H_
#define GEMM_N256_K7168_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <stdint.h>
#include <stdio.h>

#ifndef CUDA_CHECK
#define CUDA_CHECK(expr)                                                       \
  do {                                                                         \
    cudaError_t _err = (expr);                                                 \
    if (_err != cudaSuccess) {                                                 \
      fprintf(stderr, "CUDA error %s:%d: %s\n", __FILE__, __LINE__,            \
              cudaGetErrorString(_err));                                       \
    }                                                                          \
  } while (0)
#endif

#ifdef __cplusplus
extern "C" {
#endif

// C = A * B^T
// A: [M, 7168] fp16 row-major contiguous
// B: [256, 7168] fp16 row-major contiguous
// C: [M, 256] fp16 row-major contiguous
void gemm_n256_k7168_launch(const half* A, const half* B, half* C, int M,
                            cudaStream_t stream);

#ifdef __cplusplus
}
#endif

#endif  // GEMM_N256_K7168_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>

static constexpr int N_CONST = 256;
static constexpr int K_CONST = 7168;

// -------------------------
// Fallback kernel (safe for all M):
// 8 warps/block => each warp computes one output column for one row.
// grid.x = ceil(256/8)=32, grid.y = M
// -------------------------
__global__ void gemm_n256_k7168_warp_kernel(const half* __restrict__ A,
                                           const half* __restrict__ B,
                                           half* __restrict__ C,
                                           int M) {
  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;  // 0..7

  const int m = (int)blockIdx.y;
  const int n = (int)blockIdx.x * 8 + warp;

  if (m >= M || n >= N_CONST) return;

  const half* __restrict__ arow = A + (int64_t)m * K_CONST;
  const half* __restrict__ brow = B + (int64_t)n * K_CONST;

  float sum = 0.0f;

  // K_CONST is even => can use half2
  const half2* __restrict__ a2 = reinterpret_cast<const half2*>(arow);
  const half2* __restrict__ b2 = reinterpret_cast<const half2*>(brow);
  constexpr int K2 = K_CONST / 2;  // 3584

  // Each lane accumulates strided half2 pairs
  for (int k2 = lane; k2 < K2; k2 += 32) {
#if defined(__CUDA_ARCH__)
    const half2 av = __ldg(a2 + k2);
    const half2 bv = __ldg(b2 + k2);
#else
    const half2 av = a2[k2];
    const half2 bv = b2[k2];
#endif
    // Use half2 to float2 conversion
    const float2 af = __half22float2(av);
    const float2 bf = __half22float2(bv);
    sum = fmaf(af.x, bf.x, sum);
    sum = fmaf(af.y, bf.y, sum);
  }

  // Warp reduce
  for (int offset = 16; offset > 0; offset >>= 1) {
    sum += __shfl_down_sync(0xffffffff, sum, offset);
  }

  if (lane == 0) {
    C[(int64_t)m * N_CONST + n] = __float2half_rn(sum);
  }
}

static inline int div_up_host_int(int a, int b) { return (a + b - 1) / b; }

void gemm_n256_k7168_launch(const half* A, const half* B, half* C, int M,
                            cudaStream_t stream) {
  if (M <= 0) return;

  dim3 block(256, 1, 1);                 // 8 warps
  dim3 grid(div_up_host_int(N_CONST, 8), // 32
            (unsigned)M,
            1);

  gemm_n256_k7168_warp_kernel<<<grid, block, 0, stream>>>(A, B, C, M);
  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <climits>

#include "kernel.h"

static void check_input_2d_cuda_f16_contig(const torch::Tensor& t,
                                           const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.dtype() == torch::kFloat16, name, " must be float16");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
  TORCH_CHECK(t.dim() == 2, name, " must be rank-2");
}

torch::Tensor run(torch::Tensor A, torch::Tensor B) {
  check_input_2d_cuda_f16_contig(A, "A");
  check_input_2d_cuda_f16_contig(B, "B");

  const int64_t M64 = A.size(0);
  const int64_t K = A.size(1);
  const int64_t N = B.size(0);
  const int64_t Kb = B.size(1);

  TORCH_CHECK(K == 7168, "A.shape[1] must be 7168, got ", K);
  TORCH_CHECK(N == 256, "B.shape[0] must be 256, got ", N);
  TORCH_CHECK(Kb == 7168, "B.shape[1] must be 7168, got ", Kb);
  TORCH_CHECK(M64 >= 0, "M must be non-negative, got ", M64);
  TORCH_CHECK(M64 <= INT32_MAX, "M too large for this kernel, got ", M64);

  auto C = torch::empty({M64, 256},
                        torch::TensorOptions().device(A.device()).dtype(torch::kFloat16));

  const half* A_ptr = reinterpret_cast<const half*>(A.data_ptr<at::Half>());
  const half* B_ptr = reinterpret_cast<const half*>(B.data_ptr<at::Half>());
  half* C_ptr = reinterpret_cast<half*>(C.data_ptr<at::Half>());

  cudaStream_t stream = at::cuda::getDefaultCUDAStream();
  gemm_n256_k7168_launch(A_ptr, B_ptr, C_ptr, static_cast<int>(M64), stream);

  C10_CUDA_KERNEL_LAUNCH_CHECK();
  return C;
}

// kwargs-safe binding
torch::Tensor run_kwargs(torch::Tensor A, torch::Tensor B) { return run(A, B); }

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run_kwargs, "gemm_n256_k7168: C = A @ B.T (fp16, N=256, K=7168)",
        py::arg("A"), py::arg("B"));
}
